40	        .agent-controls input:focus { border-color: #e94560; }
41	        .agent-controls button { padding: 6px 12px; border: none; border-radius: 4px; cursor: pointer; font-size: 12px; font-weight: 500; }
42	        .btn-send { background: #4ecca3; color: #1a1a2e; }
