46	
47	        .conn-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; }
48	        .conn-dot.connected { background: #4ecca3; }
49	        .conn-dot.disconnected { background: #e94560; }
50	    </style>
51	</head>
52	<body>
53	    <header>
54	        <h1>All Together Now</h1>
55	        <span class="agent-count" id="agent-count"></span>
56	    </header>
57	    <div class="dashboard" id="dashboard"></div>
58	
59	    <script src="https://cdn.jsdelivr.net/npm/@xterm/xterm@5.5.0/lib/xterm.min.js"></script>
60	    <script src="https://cdn.jsdelivr.net/npm/@xterm/addon-fit@0.10.0/lib/addon-fit.min.js"></script>
61	    <script>
62	        const API_BASE = '';
63	        const agents = new Map(); // id -> { term, fitAddon, evtSource, panel }
64	
65	        const STATE_LABELS = {
66	            starting: 'Starting',
67	            running: 'Running',
68	            idle: 'Idle',
69	            awaiting_human_input: 'Awaiting Input',
70	            busy: 'Busy',
71	            blocked: 'Blocked',
72	            completed_task: 'Completed',
73	            error: 'Error',
74	            disconnected: 'Disconnected',
75	        };
76	
77	        function stateKey(stateObj) {
78	            if (typeof stateObj === 'string') return stateObj;
79	            if (stateObj && stateObj.state) return stateObj.state;
80	            return 'starting';
81	        }
82	
83	        function stateLabel(stateObj) {
84	            const key = stateKey(stateObj);
85	            return STATE_LABELS[key] || key;
86	        }
87	
88	        function createAgentPanel(agent) {
89	            const panel = document.createElement('div');
90	            panel.className = 'agent-panel';
91	            panel.id = `panel-${agent.id}`;
92	
93	            const sk = stateKey(agent.state);
94	
95	            panel.innerHTML = `
96	                <div class="agent-header">
97	                    <span class="agent-name">${agent.name}</span>
98	                    <span class="agent-role">${agent.role}</span>
99	                    <span class="spacer"></span>
100	                    <span class="conn-dot disconnected" id="conn-${agent.id}"></span>
101	                    <span class="state-badge state-${sk}" id="badge-${agent.id}">${stateLabel(agent.state)}</span>
102	                </div>
103	                <div class="agent-terminal" id="term-${agent.id}"></div>
104	                <div class="agent-controls">
105	                    <input type="text" id="input-${agent.id}" placeholder="Command for ${agent.name}...">
106	                    <button class="btn-send" data-agent="${agent.id}">Send</button>
107	                    <button class="btn-ctrl-c" data-agent="${agent.id}">^C</button>
108	                </div>
109	            `;
110	            return panel;
111	        }
112	
113	        function initTerminal(agentId) {
114	            const term = new Terminal({
115	                cursorBlink: true,
116	                fontSize: 13,
117	                fontFamily: "'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace",
118	                theme: {
119	                    background: '#0d1117',
120	                    foreground: '#c9d1d9',
121	                    cursor: '#e94560',
122	                    selectionBackground: '#264f78',
123	                },
124	            });
125	            const fitAddon = new FitAddon.FitAddon();
126	            term.loadAddon(fitAddon);
127	
128	            const container = document.getElementById(`term-${agentId}`);
129	            term.open(container);
130	            fitAddon.fit();
131	            return { term, fitAddon };
132	        }
133	
134	        function connectSSE(agentId) {
135	            const connDot = document.getElementById(`conn-${agentId}`);
136	            const evtSource = new EventSource(`${API_BASE}/api/agents/${agentId}/sse`);
137	            const agent = agents.get(agentId);
138	
139	            evtSource.onopen = () => {
140	                connDot.className = 'conn-dot connected';
141	            };
142	
143	            evtSource.onmessage = (event) => {
144	                const bytes = Uint8Array.from(atob(event.data), c => c.charCodeAt(0));
145	                agent.term.write(bytes);
146	            };
147	
148	            evtSource.onerror = () => {
149	                connDot.className = 'conn-dot disconnected';
150	                evtSource.close();
151	                setTimeout(() => connectSSE(agentId), 2000);
152	            };
153	
154	            agent.evtSource = evtSource;
155	        }
156	
157	        function setupControls(agentId) {
158	            const input = document.getElementById(`input-${agentId}`);
159	            const panel = document.getElementById(`panel-${agentId}`);
160	            const sendBtn = panel.querySelector('.btn-send');
161	            const ctrlcBtn = panel.querySelector('.btn-ctrl-c');
162	
163	            function doSend() {
164	                const text = input.value;
165	                if (text) {
166	                    fetch(`${API_BASE}/api/agents/${agentId}/input`, {
167	                        method: 'POST',
168	                        headers: { 'Content-Type': 'application/json' },
169	                        body: JSON.stringify({ text }),
170	                    });
171	                    input.value = '';
172	                }
173	                input.focus();
174	            }
175	
176	            sendBtn.addEventListener('click', doSend);
177	            input.addEventListener('keydown', (e) => {
178	                if (e.key === 'Enter') doSend();
179	            });
180	
181	            ctrlcBtn.addEventListener('click', () => {
182	                fetch(`${API_BASE}/api/agents/${agentId}/ctrl-c`, { method: 'POST' });
183	                input.focus();
184	            });
185	        }
186	
187	        // Poll agent states every 2 seconds
188	        async function pollStates() {
189	            try {
190	                const res = await fetch(`${API_BASE}/api/agents`);
191	                if (!res.ok) return;
192	                const list = await res.json();
193	                for (const agent of list) {
194	                    const badge = document.getElementById(`badge-${agent.id}`);
195	                    if (badge) {
196	                        const sk = stateKey(agent.state);
197	                        badge.className = `state-badge state-${sk}`;
198	                        badge.textContent = stateLabel(agent.state);
199	                    }
200	                }
201	            } catch (_) { /* ignore */ }
202	        }
203	
204	        async function init() {
205	            const res = await fetch(`${API_BASE}/api/agents`);
206	            const agentList = await res.json();
207	
208	            const dashboard = document.getElementById('dashboard');
209	            const count = agentList.length;
210	            document.getElementById('agent-count').textContent = `${count} agent${count !== 1 ? 's' : ''}`;
211	
212	            // Choose grid columns based on agent count
213	            if (count <= 1) dashboard.className = 'dashboard cols-1';
214	            else if (count <= 2) dashboard.className = 'dashboard cols-2';
