2	
3	#[derive(Deserialize)]
4	pub struct PatchRequest {
5	    pub etag: String,
6	    pub ops: Vec<PatchOp>,
7	}
8	
9	#[derive(Deserialize)]
10	#[serde(tag = "op")]
11	pub enum PatchOp {
12	    #[serde(rename = "replace")]
13	    Replace {
14	        #[serde(rename = "match")]
15	        match_str: String,
16	        replace: String,
17	    },
18	    #[serde(rename = "append_after")]
19	    AppendAfter {
20	        #[serde(rename = "match")]
21	        match_str: String,
22	        text: String,
23	    },
24	    #[serde(rename = "insert_before")]
25	    InsertBefore {
26	        #[serde(rename = "match")]
27	        match_str: String,
28	        text: String,
29	    },
30	    #[serde(rename = "delete")]
31	    Delete {
32	        #[serde(rename = "match")]
33	        match_str: String,
34	    },
35	}
36	
37	#[derive(Debug, Serialize)]
38	pub struct PatchError {
39	    pub op_index: usize,
40	    pub match_str: String,
41	}
42	
43	/// Apply patch operations sequentially to content.
44	/// Each op works on the result of the previous op.
45	/// Returns the patched content, or an error if a match string was not found.
46	pub fn apply_ops(content: &str, ops: &[PatchOp]) -> Result<String, PatchError> {
47	    let mut result = content.to_string();
48	    for (i, op) in ops.iter().enumerate() {
49	        result = apply_one(&result, i, op)?;
50	    }
51	    Ok(result)
52	}
53	
54	fn apply_one(content: &str, index: usize, op: &PatchOp) -> Result<String, PatchError> {
55	    match op {
56	        PatchOp::Replace { match_str, replace } => {
57	            if !content.contains(match_str.as_str()) {
58	                return Err(not_found(index, match_str));
59	            }
60	            Ok(content.replacen(match_str, replace, 1))
61	        }
62	        PatchOp::AppendAfter { match_str, text } => {
63	            let lines: Vec<&str> = content.lines().collect();
64	            let pos = lines
65	                .iter()
66	                .position(|l| l.contains(match_str.as_str()))
67	                .ok_or_else(|| not_found(index, match_str))?;
68	            let mut out = Vec::with_capacity(lines.len() + 1);
69	            out.extend_from_slice(&lines[..=pos]);
70	            out.push(text);
71	            out.extend_from_slice(&lines[pos + 1..]);
72	            Ok(join_preserving_trailing(content, &out))
73	        }
74	        PatchOp::InsertBefore { match_str, text } => {
75	            let lines: Vec<&str> = content.lines().collect();
76	            let pos = lines
77	                .iter()
78	                .position(|l| l.contains(match_str.as_str()))
79	                .ok_or_else(|| not_found(index, match_str))?;
80	            let mut out = Vec::with_capacity(lines.len() + 1);
81	            out.extend_from_slice(&lines[..pos]);
82	            out.push(text);
83	            out.extend_from_slice(&lines[pos..]);
84	            Ok(join_preserving_trailing(content, &out))
85	        }
86	        PatchOp::Delete { match_str } => {
87	            if !content.contains(match_str.as_str()) {
88	                return Err(not_found(index, match_str));
89	            }
90	            Ok(content.replacen(match_str, "", 1))
91	        }
92	    }
93	}
94	
95	fn not_found(op_index: usize, match_str: &str) -> PatchError {
96	    PatchError {
97	        op_index,
98	        match_str: match_str.to_string(),
99	    }
100	}
101	
102	fn join_preserving_trailing(original: &str, lines: &[&str]) -> String {
103	    let mut joined = lines.join("\n");
104	    if original.ends_with('\n') {
105	        joined.push('\n');
106	    }
107	    joined
108	}
109	
110	#[cfg(test)]
111	mod tests {
112	    use super::*;
113	
114	    #[test]
115	    fn replace_op_works() {
116	        let content = "| REQ-003 | REQUESTED |\n| REQ-004 | DONE |";
117	        let ops = vec![PatchOp::Replace {
118	            match_str: "| REQ-003 | REQUESTED |".to_string(),
119	            replace: "| REQ-003 | IN PROGRESS |".to_string(),
120	        }];
121	        let result = apply_ops(content, &ops).unwrap();
122	        assert_eq!(result, "| REQ-003 | IN PROGRESS |\n| REQ-004 | DONE |");
123	    }
124	
125	    #[test]
126	    fn replace_only_first_occurrence() {
127	        let content = "AAA\nAAA\nBBB";
128	        let ops = vec![PatchOp::Replace {
129	            match_str: "AAA".to_string(),
130	            replace: "ZZZ".to_string(),
131	        }];
132	        let result = apply_ops(content, &ops).unwrap();
133	        assert_eq!(result, "ZZZ\nAAA\nBBB");
134	    }
135	
136	    #[test]
137	    fn append_after_inserts_on_next_line() {
138	        let content = "## Requirements\n| REQ-001 | DONE |";
139	        let ops = vec![PatchOp::AppendAfter {
140	            match_str: "## Requirements".to_string(),
141	            text: "| REQ-002 | NEW |".to_string(),
142	        }];
143	        let result = apply_ops(content, &ops).unwrap();
144	        assert_eq!(
145	            result,
146	            "## Requirements\n| REQ-002 | NEW |\n| REQ-001 | DONE |"
147	        );
148	    }
149	
150	    #[test]
151	    fn insert_before_inserts_above_line() {
152	        let content = "## Header\n## Footer";
153	        let ops = vec![PatchOp::InsertBefore {
154	            match_str: "## Footer".to_string(),
155	            text: "## Notes".to_string(),
156	        }];
157	        let result = apply_ops(content, &ops).unwrap();
158	        assert_eq!(result, "## Header\n## Notes\n## Footer");
159	    }
160	
161	    #[test]
162	    fn delete_removes_match() {
163	        let content = "line1\ndelete-me\nline3";
164	        let ops = vec![PatchOp::Delete {
165	            match_str: "delete-me\n".to_string(),
166	        }];
167	        let result = apply_ops(content, &ops).unwrap();
168	        assert_eq!(result, "line1\nline3");
169	    }
170	
171	    #[test]
172	    fn match_not_found_returns_error() {
173	        let content = "hello world";
174	        let ops = vec![PatchOp::Replace {
175	            match_str: "no such text".to_string(),
176	            replace: "x".to_string(),
177	        }];
178	        let err = apply_ops(content, &ops).unwrap_err();
179	        assert_eq!(err.op_index, 0);
180	        assert_eq!(err.match_str, "no such text");
181	    }
