        .wiki
        .get_page(&title)
        .await
        .ok_or_else(|| StatusCode::NOT_FOUND.into_response())?;

    let current_etag = content_etag(&page.content);
    if patch.etag != current_etag {
        return Err(conflict_response(&page, &current_etag));
    }

