            document.getElementById('wiki-content').innerHTML = data.html;
            document.getElementById('wiki-content').style.display = '';
            document.getElementById('wiki-edit-area').style.display = 'none';
            document.getElementById('wiki-edit-btn').style.display = '';
            document.getElementById('wiki-save-btn').style.display = 'none';
            document.getElementById('wiki-cancel-btn').style.display = 'none';
            document.getElementById('wiki-conflict').style.display = 'none';
            document.getElementById('wiki-editor').value = data.content;

            // Wire up wiki-link clicks
            document.querySelectorAll('#wiki-content a.wiki-link').forEach(a => {
                a.addEventListener('click', (e) => {
                    e.preventDefault();
                    const target = a.getAttribute('data-wiki-link');
                    if (target) wikiOpenPage(target);
                });
            });

            wikiLoadPageList();
        } catch (_) {}
    }

    function wikiToggleEdit() {
        wikiEditing = true;
        document.getElementById('wiki-content').style.display = 'none';
        document.getElementById('wiki-edit-area').style.display = 'flex';
        document.getElementById('wiki-edit-btn').style.display = 'none';
        document.getElementById('wiki-save-btn').style.display = '';
        document.getElementById('wiki-cancel-btn').style.display = '';
    }

    function wikiCancelEdit() {
        wikiEditing = false;
        document.getElementById('wiki-content').style.display = '';
        document.getElementById('wiki-edit-area').style.display = 'none';
        document.getElementById('wiki-edit-btn').style.display = '';
        document.getElementById('wiki-save-btn').style.display = 'none';
        document.getElementById('wiki-cancel-btn').style.display = 'none';
        document.getElementById('wiki-conflict').style.display = 'none';
    }

    async function wikiSave() {
        if (!wikiCurrentPage) return;
        const content = document.getElementById('wiki-editor').value;
        const headers = { 'Content-Type': 'application/json' };
        if (wikiCurrentEtag) headers['If-Match'] = wikiCurrentEtag;

        try {
            const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(wikiCurrentPage)}`, {
                method: 'PUT',
                headers,
                body: JSON.stringify({ content }),
            });
            if (res.status === 409) {
                const data = await res.json();
                document.getElementById('wiki-conflict').textContent =
                    `Conflict: page was modified by another user. Current version shown below. Your edits are preserved in the editor.`;
                document.getElementById('wiki-conflict').style.display = '';
                wikiCurrentEtag = data.current_etag;
                return;
            }
            if (res.ok) {
                wikiCurrentEtag = res.headers.get('ETag');
                wikiOpenPage(wikiCurrentPage);
            }
        } catch (_) {}
    }

    async function wikiNewPage() {
        const input = document.getElementById('wiki-new-title');
        const title = input.value.trim();
        if (!title) return;

        try {
            const res = await fetch(`${API_BASE}/api/wiki/${encodeURIComponent(title)}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content: `# ${title}\n\n` }),
            });
            if (res.ok || res.status === 201) {
                input.value = '';
                wikiOpenPage(title);
            }
        } catch (_) {}
    }
</script>

